using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary (default: 3).
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using DocSummary.Models;

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    SummarizeResponse Summarize(string documentText, int maxSentences);
}

using System.Text.RegularExpressions;
using DocSummary.Models;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarizer that scores sentences by word frequency
/// and returns the highest-ranked ones in their original order.
/// </summary>
public partial class DocumentSummarizer : IDocumentSummarizer
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been","being",
        "have","has","had","do","does","did","will","would","shall","should","may",
        "might","must","can","could","in","on","at","to","for","of","with","by",
        "from","as","into","through","during","before","after","above","below",
        "between","out","off","over","under","again","further","then","once",
        "it","its","this","that","these","those","i","me","my","we","our","you",
        "your","he","him","his","she","her","they","them","their","what","which",
        "who","whom","how","not","no","nor","so","if","about","up","each","all",
        "both","few","more","most","other","some","such","very","just","also"
    };

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"\b[a-zA-Z]+\b")]
    private static partial Regex WordTokenizer();

    public SummarizeResponse Summarize(string documentText, int maxSentences)
    {
        var sentences = SentenceSplitter()
            .Split(documentText.Trim())
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .ToList();

        if (sentences.Count == 0)
        {
            return new SummarizeResponse
            {
                Summary = string.Empty,
                OriginalSentenceCount = 0,
                SummarySentenceCount = 0
            };
        }

        if (sentences.Count <= maxSentences)
        {
            return new SummarizeResponse
            {
                Summary = string.Join(" ", sentences),
                OriginalSentenceCount = sentences.Count,
                SummarySentenceCount = sentences.Count
            };
        }

        // Build word frequency map (excluding stop words)
        var wordFrequency = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (Match match in WordTokenizer().Matches(sentence))
            {
                var word = match.Value;
                if (!StopWords.Contains(word) && word.Length > 1)
                {
                    wordFrequency[word] = wordFrequency.GetValueOrDefault(word) + 1;
                }
            }
        }

        // Score each sentence
        var scored = sentences
            .Select((text, index) =>
            {
                double score = WordTokenizer().Matches(text)
                    .Sum(m => wordFrequency.GetValueOrDefault(m.Value));
                // Normalize by sentence length to avoid bias toward long sentences
                int wordCount = WordTokenizer().Matches(text).Count;
                if (wordCount > 0) score /= wordCount;
                return (Index: index, Text: text, Score: score);
            })
            .ToList();

        // Pick top sentences, then restore original order
        var topSentences = scored
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index)
            .Select(s => s.Text)
            .ToList();

        return new SummarizeResponse
        {
            Summary = string.Join(" ", topSentences),
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = topSentences.Count
        };
    }
}

using Microsoft.AspNetCore.Mvc;
using DocSummary.Models;
using DocSummary.Services;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizer _summarizer;

    public SummarizeController(IDocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var result = _summarizer.Summarize(request.DocumentText, request.MaxSentences);
        return Ok(result);
    }
}

